/* NODES: PROCESAMIENTO PROFESIONAL DE NEGOCIO */
const inputData = $input.all();
const business = { transactions: [] };

function cleanCurrency(val) {
  if (val === undefined || val === null || val === "") return 0;
  try {
    let s = String(val).replace(/[€*%\s\(\)]/g, '').trim();
    if (s === "" || s === "-") return 0;
    if (s.includes(',') && s.includes('.')) s = s.replace(/\./g, '').replace(',', '.');
    else if (s.includes(',')) s = s.replace(',', '.');
    else if (s.includes('.')) {
      const parts = s.split('.');
      if (parts[parts.length-1].length === 3) s = s.replace(/\./g, '');
    }
    return parseFloat(s) || 0;
  } catch (e) { return 0; }
}

for (const item of inputData) {
  const json = item.json; if (!json) continue;
  if (json.Monto !== undefined) {
    const amount = cleanCurrency(json.Monto);
    const originalType = String(json.Tipo || '').trim();
    let rawType = originalType.toUpperCase();
    let rawConcept = String(json.Concepto || '').trim().toUpperCase();

    // Normalize underscore for internal classification
    let typeTag = rawType.replace(/_/g, ' ');
    let type = 'Venta';

    if (rawType.includes('COMPRA')) {
       type = 'Compra';
    } else if (rawType.includes('ADS') || rawType.includes('PUBLICIDAD') || rawConcept.includes('PUBLICIDAD')) {
       type = 'Publicidad';
    } else if (rawType.includes('ENVI') || rawConcept.includes('ENVI') || rawConcept.includes('SHIPPING')) {
       type = 'Envío';
    } else if (rawType.includes('DEVOLI') || rawType.includes('DEVOLU')) {
       if (rawType.includes('FAVOR') || rawConcept.includes('FAVOR')) type = 'Devolución a favor';
       else if (rawType.includes('CONTRA') || rawConcept.includes('CONTRA')) type = 'Devolución en contra';
       else type = 'Devolución en contra';
    } else {
       // Fallback to formatted original Tipo if it's not simply "VENTA"
       if (rawType !== 'VENTA' && rawType !== '') type = typeTag.charAt(0) + typeTag.slice(1).toLowerCase();
    }

    business.transactions.push({
      date: json.Fecha || '-',
      item: json.Concepto || '-',
      type: type,
      raw_type: originalType,
      amount: amount
    });
  }
}

return [{ json: { business } }];
